app = Flask(__name__)

ALLOWED_TAGS = {"b", "strong", "i", "em", "br"}
TAG_RE = re.compile(r"<\s*/?\s*([a-zA-Z0-9]+)(?:\s[^>]*)?>")

def sanitize_basic_formatting(user_html: str) -> str:
    if not user_html:
        return ""
    s = str(user_html)

    placeholders = {}
    def stash_tag(m):
        full = m.group(0)
        tag = (m.group(1) or "").lower()
        if tag in ALLOWED_TAGS:
            key = f"__TAG{len(placeholders)}__"
            placeholders[key] = full
            return key
        return full

    s = TAG_RE.sub(stash_tag, s)
    s = html.escape(s, quote=True)
    for k, v in placeholders.items():
        s = s.replace(html.escape(k, quote=True), v)
    return s

