@app.get("/dashboard")
def dashboard():
    name = (request.args.get("name") or "Guest").strip()[:80]
    location = (request.args.get("location") or "Unknown").strip()[:120]
    bio = (request.args.get("bio") or "Add a short bio using <b>bold</b> or <i>italic</i>.").strip()[:2000]
    status = (request.args.get("status") or "Feeling productive.").strip()[:800]

    name_plain = html.escape(name, quote=True)
    location_plain = html.escape(location, quote=True)
    bio_html = sanitize_basic_formatting(bio)
    status_html = sanitize_basic_formatting(status)

    from datetime import datetime, timezone
    now_text = datetime.now(timezone.utc).strftime("UTC %Y-%m-%d %H:%M")

    return render_template_string(
        TEMPLATE,
        name_plain=name_plain,
        location_plain=location_plain,
        bio_html=bio_html,
        status_html=status_html,
        now_text=now_text,
    )

if __name__ == "__main__":
    app.run(debug=True)